sys_script_include.script:
/**
 * ProblemUtils
 * 
 * Description: Utility class for Problem Management operations.
 * Handles problem creation from incidents, state tracking, and notifications.
 * Only L2 Support Team members are allowed to create problems.
 * 
 * Usage:
 *   var pu = new ProblemUtils();
 *   pu.createProblemFromIncident(incidentGr);
 *   pu.isL2Agent();  // Check if current user can create problems
 */

var ProblemUtils = Class.create();
ProblemUtils.prototype = {
    initialize: function() {},

    /**
     * Check if the current user is a member of the L2 Support Team
     * @returns {boolean} - true if user is L2 agent
     */
    isL2Agent: function() {
        if (gs.hasRole('admin')) return true;
        if (gs.hasRole('itsm_l2_agent')) return true;

        // Fallback: check if user belongs to L2 Support Team group
        var l2Group = new GlideRecord('sys_user_group');
        if (l2Group.get('name', 'L2 Support Team')) {
            var member = new GlideRecord('sys_user_grmember');
            member.addQuery('user', gs.getUserID());
            member.addQuery('group', l2Group.getUniqueValue());
            member.query();
            if (member.hasNext()) return true;
        }

        return false;
    },

    /**
     * Create a problem record from an existing incident
     * @param {GlideRecord} incidentGr - The incident GlideRecord
     * @returns {Object} - {success: boolean, number: string, error: string}
     */
    createProblemFromIncident: function(incidentGr) {
        if (!incidentGr) {
            return {success: false, error: 'No incident provided'};
        }

        // Check permission
        if (!this.isL2Agent()) {
            return {success: false, error: 'Only L2 Support Team members can create problems'};
        }

        try {
            var problemGr = new GlideRecord('problem');
            problemGr.initialize();

            // Copy relevant fields from incident
            problemGr.short_description = 'Problem: ' + incidentGr.getValue('short_description');
            problemGr.description = this.buildProblemDescription(incidentGr);
            problemGr.category = incidentGr.getValue('category');
            problemGr.subcategory = incidentGr.getValue('subcategory');
            problemGr.urgency = incidentGr.getValue('urgency');
            problemGr.impact = incidentGr.getValue('impact');

            // Set assignment to original L1 group for investigation
            var originalGroup = incidentGr.getValue('u_original_l1_group');
            if (originalGroup) {
                problemGr.assignment_group = originalGroup;
            } else {
                problemGr.assignment_group = incidentGr.getValue('assignment_group');
            }

            // Set caller as the problem coordinator
            problemGr.assigned_to = gs.getUserID();

            // Link to the source incident
            problemGr.setValue('u_source_incident', incidentGr.getUniqueValue());

            var problemSysId = problemGr.insert();

            if (problemSysId) {
                // Link the incident to this problem
                this.linkIncidentToProblem(incidentGr.getUniqueValue(), problemSysId);

                // Link problem to incident in the related records
                this.addProblemToIncident(incidentGr.getUniqueValue(), problemSysId);

                // Send notification
                this.sendProblemCreatedNotification(problemGr);

                gs.info('ProblemUtils: Problem ' + problemGr.number + 
                         ' created from incident ' + incidentGr.number);

                return {
                    success: true,
                    number: problemGr.number,
                    sys_id: problemSysId,
                    message: 'Problem ' + problemGr.number + ' has been created successfully.'
                };
            } else {
                return {success: false, error: 'Failed to create problem record'};
            }
        } catch (e) {
            gs.error('ProblemUtils: Error creating problem - ' + e.message);
            return {success: false, error: e.message};
        }
    },

    /**
     * Build a comprehensive problem description from the source incident
     * @param {GlideRecord} incidentGr - The source incident
     * @returns {string} - Formatted description
     */
    buildProblemDescription: function(incidentGr) {
        var description = '=== Problem created from Incident ' + incidentGr.number + ' ===\n\n';

        description += 'Original Incident Details:\n';
        description += '  Short Description: ' + incidentGr.getValue('short_description') + '\n';
        description += '  Category/Subcategory: ' + incidentGr.getDisplayValue('category') + 
                       ' / ' + incidentGr.getDisplayValue('subcategory') + '\n';
        description += '  Caller: ' + incidentGr.getDisplayValue('caller_id') + '\n';
        description += '  Urgency/Impact: ' + incidentGr.getDisplayValue('urgency') + 
                       ' / ' + incidentGr.getDisplayValue('impact') + '\n';
        description += '  Assignment Group: ' + incidentGr.getDisplayValue('assignment_group') + '\n\n';

        description += 'Original Description:\n';
        description += incidentGr.getValue('description') + '\n\n';
        description += '=== End of Incident Details ===\n\n';

        return description;
    },

    /**
     * Link an incident to a problem using the problem_id field on incident
     * @param {string} incidentSysId - Incident sys_id
     * @param {string} problemSysId - Problem sys_id
     */
    linkIncidentToProblem: function(incidentSysId, problemSysId) {
        var incGr = new GlideRecord('incident');
        if (incGr.get(incidentSysId)) {
            incGr.problem_id = problemSysId;

            // Add work note to incident
            var notes = incGr.getValue('work_notes') || '';
            var problemGr = new GlideRecord('problem');
            problemGr.get(problemSysId);

            var note = '\n[Problem Created] Problem ' + problemGr.number + 
                       ' has been created by ' + gs.getUserDisplayName() + 
                       ' to track this issue.';
            incGr.work_notes = note;

            incGr.update();
        }
    },

    /**
     * Add problem as related record to incident (via task table relationship)
     * @param {string} incidentSysId - Incident sys_id
     * @param {string} problemSysId - Problem sys_id
     */
    addProblemToIncident: function(incidentSysId, problemSysId) {
        // Using the standard related record mechanism
        var taskRel = new GlideRecord('task_relates_to');
        taskRel.initialize();
        taskRel.task_to = problemSysId;
        taskRel.task_from = incidentSysId;
        taskRel.type = 'problem_from_incident';
        taskRel.insert();
    },

    /**
     * Send notification when a new problem is created
     * @param {GlideRecord} problemGr - The problem GlideRecord
     */
    sendProblemCreatedNotification: function(problemGr) {
        if (!problemGr) return;

        try {
            problemGr.setEvent('problem.created', problemGr.getUniqueValue(),
                'Problem ' + problemGr.number + ' has been created from incident');

            gs.info('ProblemUtils: Notification sent for new problem ' + problemGr.number);
        } catch (e) {
            gs.error('ProblemUtils: Error sending notification - ' + e.message);
        }
    },

    /**
     * Send notification when problem state changes
     * @param {GlideRecord} problemGr - The problem GlideRecord
     * @param {string} previousState - Previous state value
     */
    sendProblemStateChangeNotification: function(problemGr, previousState) {
        if (!problemGr) return;

        try {
            var currentState = problemGr.getValue('state');
            if (currentState !== previousState) {
                problemGr.setEvent('problem.state_changed', problemGr.getUniqueValue(),
                    'Problem ' + problemGr.number + ' state changed');

                gs.info('ProblemUtils: State change notification sent for problem ' + 
                         problemGr.number);
            }
        } catch (e) {
            gs.error('ProblemUtils: Error sending state change notification - ' + e.message);
        }
    },

    /**
     * Get available problem states
     * @returns {Object} - Map of state values to labels
     */
    getProblemStates: function() {
        return {
            '1': 'New',
            '2': 'Under Investigation',
            '3': 'Root Cause Identified',
            '4': 'Known Error',
            '5': 'Resolution Identified',
            '6': 'Resolved',
            '7': 'Closed'
        };
    },

    type: 'ProblemUtils'
};
